    93→function validateForm(data, rules) {
    94→    const errors = {};
    95→
    96→    for (const [field, rule] of Object.entries(rules)) {
    97→        const value = data[field];
    98→
    99→        if (rule.required && (!value || value.trim() === '')) {
   100→            errors[field] = `${rule.label || field} is required`;
