    id: int
    phone_id: int
    quantity: int
    unit_price: float
    phone: Optional[PhoneOut] = None

    model_config = {"from_attributes": True}

    @field_validator("unit_price", mode="before")
    @classmethod
    def coerce_decimal(cls, v):
        return float(v)


