    customer_name: str
    customer_phone: str
    customer_address: str
    note: Optional[str] = None
    total_amount: float
    status: str
    created_at: datetime
    items: list[OrderItemOut] = []

    model_config = {"from_attributes": True}

    @field_validator("total_amount", mode="before")
    @classmethod
    def coerce_decimal(cls, v):
        return float(v)

