from fastapi import HTTPException
from app.models.phone import Phone, PhoneCategory, PhoneOrder, PhoneOrderItem
from app.schemas.phone import OrderCreate


def get_categories(db: Session):
    return db.query(PhoneCategory).order_by(PhoneCategory.id).all()


def get_phones(db: Session, category_slug: str = None, featured: bool = False, search: str = None):
    q = db.query(Phone).options(joinedload(Phone.category))
    if category_slug:
        q = q.join(PhoneCategory).filter(PhoneCategory.slug == category_slug)
    if featured:
        q = q.filter(Phone.is_featured == 1)
    if search:
        q = q.filter(Phone.name.ilike(f"%{search}%"))
    return q.order_by(Phone.id).all()


def get_phone(db: Session, phone_id: int):
    phone = db.query(Phone).options(joinedload(Phone.category)).filter(Phone.id == phone_id).first()
    if not phone:
        raise HTTPException(status_code=404, detail="Không tìm thấy sản phẩm")
    return phone


def create_order(db: Session, data: OrderCreate):
    if not data.items:
        raise HTTPException(status_code=400, detail="Giỏ hàng trống")

    total = 0
    order_items = []
    for item in data.items:
        phone = db.query(Phone).filter(Phone.id == item.phone_id).first()
        if not phone:
            raise HTTPException(status_code=404, detail=f"Sản phẩm #{item.phone_id} không tồn tại")
        if phone.stock < item.quantity:
            raise HTTPException(status_code=400, detail=f"'{phone.name}' không đủ hàng")
        total += float(phone.price) * item.quantity
        order_items.append((phone, item.quantity))

    order = PhoneOrder(
        customer_name=data.customer_name,
        customer_phone=data.customer_phone,
        customer_address=data.customer_address,
        note=data.note,
        total_amount=total,
    )
    db.add(order)
    db.flush()

    for phone, qty in order_items:
        db.add(PhoneOrderItem(
            order_id=order.id,
            phone_id=phone.id,
            quantity=qty,
            unit_price=float(phone.price),
        ))
        phone.stock -= qty

    db.commit()
    db.refresh(order)
    return order

