from fastapi import APIRouter, Depends, Query
from typing import Optional
from sqlalchemy.orm import Session
from app.api.deps import get_db
from app.schemas.phone import CategoryOut, PhoneOut, OrderCreate, OrderOut
from app.services import phone_service

router = APIRouter(prefix="/api/phones", tags=["phones"])


@router.get("/categories", response_model=list[CategoryOut])
def list_categories(db: Session = Depends(get_db)):
    return phone_service.get_categories(db)


@router.get("", response_model=list[PhoneOut])
def list_phones(
    category: Optional[str] = Query(None),
    featured: bool = Query(False),
    search: Optional[str] = Query(None),
    db: Session = Depends(get_db),
):
    return phone_service.get_phones(db, category_slug=category, featured=featured, search=search)


@router.get("/{phone_id}", response_model=PhoneOut)
def get_phone(phone_id: int, db: Session = Depends(get_db)):
    return phone_service.get_phone(db, phone_id)


@router.post("/orders", response_model=OrderOut)
def create_order(data: OrderCreate, db: Session = Depends(get_db)):
    return phone_service.create_order(db, data)

