   NEXUS PHONE — Dark Tech Aesthetic
   Oxanium (display) + DM Sans (body)
   Palette: Deep space navy + Electric cyan
   ============================================= */

/* RESET */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --font-display: 'Oxanium', sans-serif;
  --font-body: 'DM Sans', sans-serif;

  --bg:         #06090f;
  --bg-card:    #0d1117;
  --bg-card2:   #111827;
  --surface:    #161d2a;
  --border:     rgba(255,255,255,0.07);
  --border2:    rgba(0,212,255,0.2);

  --cyan:       #00d4ff;
  --cyan-dim:   #00a8cc;
  --cyan-glow:  rgba(0,212,255,0.15);
  --gold:       #f0c040;

  --text:       #eef2f8;
  --text-muted: #6b7a99;
  --text-dim:   #4a5568;

  --error:      #ff4757;
  --success:    #2ed573;

  --r-sm:  6px;
  --r-md:  12px;
  --r-lg:  20px;
  --r-xl:  28px;
  --ease:  cubic-bezier(.4,0,.2,1);
}

html { scroll-behavior: smooth; }

body {
  font-family: var(--font-body);
  background: var(--bg);
  color: var(--text);
  line-height: 1.65;
  -webkit-font-smoothing: antialiased;
  overflow-x: hidden;
}

/* =============================================
   HEADER
   ============================================= */
.header {
  position: sticky;
  top: 0;
  z-index: 100;
  background: rgba(6,9,15,0.85);
  backdrop-filter: blur(16px);
  border-bottom: 1px solid var(--border);
}

.header__inner {
  max-width: 1280px;
  margin: 0 auto;
  padding: 0 24px;
  height: 64px;
  display: flex;
  align-items: center;
  gap: 32px;
}

.logo {
  display: flex;
  align-items: center;
  gap: 8px;
  text-decoration: none;
  flex-shrink: 0;
}

.logo__hex {
  font-size: 22px;
  color: var(--cyan);
  line-height: 1;
  filter: drop-shadow(0 0 8px var(--cyan));
}

.logo__text {
  font-family: var(--font-display);
  font-size: 18px;
  font-weight: 800;
  color: var(--text);
  letter-spacing: 0.05em;
  text-transform: uppercase;
}

.logo__text em {
  font-style: normal;
  color: var(--cyan);
}

.nav {
  display: flex;
  align-items: center;
  gap: 4px;
  flex: 1;
}

.nav__link {
  font-family: var(--font-display);
  font-size: 12.5px;
  font-weight: 500;
  letter-spacing: 0.06em;
  color: var(--text-muted);
  text-decoration: none;
  padding: 6px 14px;
  border-radius: var(--r-sm);
  transition: all 0.2s var(--ease);
  white-space: nowrap;
}

.nav__link:hover,
.nav__link.active {
  color: var(--cyan);
  background: var(--cyan-glow);
}

.header__actions {
  display: flex;
  align-items: center;
  gap: 12px;
  flex-shrink: 0;
}

.search-wrap {
  display: flex;
  align-items: center;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--r-sm);
  overflow: hidden;
  transition: border-color 0.2s;
}

.search-wrap:focus-within { border-color: var(--cyan-dim); }

.search-input {
  background: transparent;
  border: none;
  outline: none;
  color: var(--text);
  font-family: var(--font-body);
  font-size: 13px;
  padding: 8px 12px;
  width: 200px;
}

.search-input::placeholder { color: var(--text-dim); }

.search-btn {
  background: transparent;
  border: none;
  cursor: pointer;
  color: var(--text-muted);
  padding: 8px 12px;
  display: flex;
  align-items: center;
  transition: color 0.2s;
}

.search-btn:hover { color: var(--cyan); }

.cart-btn {
  position: relative;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--r-sm);
  cursor: pointer;
  color: var(--text);
  padding: 9px 12px;
  display: flex;
  align-items: center;
  transition: all 0.2s;
}

.cart-btn:hover {
  border-color: var(--cyan-dim);
  color: var(--cyan);
}

.cart-badge {
  position: absolute;
  top: -6px;
  right: -6px;
  background: var(--cyan);
  color: #000;
  font-family: var(--font-display);
  font-size: 10px;
  font-weight: 700;
  width: 18px;
  height: 18px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
}

/* =============================================
   HERO
   ============================================= */
.hero {
  position: relative;
  min-height: 90vh;
  display: flex;
  align-items: center;
  overflow: hidden;
  padding: 80px 24px;
}

.hero__bg {
  position: absolute;
  inset: 0;
  pointer-events: none;
}

.hero__orb {
  position: absolute;
  border-radius: 50%;
  filter: blur(80px);
  opacity: 0.35;
}

.hero__orb--1 {
  width: 600px;
  height: 600px;
  background: radial-gradient(circle, #003d52 0%, transparent 70%);
  top: -200px;
  left: -100px;
  animation: drift1 12s ease-in-out infinite alternate;
}

.hero__orb--2 {
  width: 500px;
  height: 500px;
  background: radial-gradient(circle, #001a33 0%, transparent 70%);
  bottom: -150px;
  right: 100px;
  animation: drift2 15s ease-in-out infinite alternate;
}

.hero__orb--3 {
  width: 300px;
  height: 300px;
  background: radial-gradient(circle, #00d4ff30 0%, transparent 70%);
  top: 30%;
  right: 30%;
  animation: drift1 20s ease-in-out infinite alternate-reverse;
}

@keyframes drift1 {
  from { transform: translate(0, 0) scale(1); }
  to   { transform: translate(40px, 30px) scale(1.1); }
}
@keyframes drift2 {
  from { transform: translate(0, 0); }
  to   { transform: translate(-30px, -40px); }
}

.hero__content {
  position: relative;
  z-index: 2;
  max-width: 600px;
  animation: fadeUp 0.8s var(--ease) both;
  margin: 0 auto 0 0;
  max-width: 1280px;
  width: 100%;
  padding: 0 max(24px, calc((100% - 1280px)/2));
}

@keyframes fadeUp {
  from { opacity: 0; transform: translateY(30px); }
  to   { opacity: 1; transform: translateY(0); }
}

.hero__eyebrow {
  font-family: var(--font-display);
  font-size: 12px;
  font-weight: 500;
  letter-spacing: 0.15em;
  color: var(--cyan);
  text-transform: uppercase;
  margin-bottom: 20px;
}

.hero__title {
  font-family: var(--font-display);
  font-size: clamp(48px, 7vw, 88px);
  font-weight: 800;
  line-height: 1.0;
  letter-spacing: -0.02em;
  margin-bottom: 24px;
  color: var(--text);
}

.hero__title span {
  color: var(--cyan);
  text-shadow: 0 0 40px var(--cyan-glow);
}

.hero__sub {
  font-size: 16px;
  color: var(--text-muted);
  line-height: 1.7;
  margin-bottom: 36px;
  max-width: 460px;
}

.hero__cta {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
}

/* Hero phone visual */
.hero__visual {
  position: absolute;
  right: 8%;
  top: 50%;
  transform: translateY(-50%);
  z-index: 1;
  animation: floatPhone 6s ease-in-out infinite;
}

@keyframes floatPhone {
  0%, 100% { transform: translateY(-50%) rotate(-3deg); }
  50%       { transform: translateY(calc(-50% - 20px)) rotate(3deg); }
}

.phone-frame {
  width: 160px;
  height: 280px;
  background: linear-gradient(145deg, var(--surface) 0%, var(--bg-card) 100%);
  border: 1px solid var(--border2);
  border-radius: 28px;
  box-shadow: 0 0 60px rgba(0,212,255,0.12), 0 40px 80px rgba(0,0,0,0.6), inset 0 1px 0 rgba(255,255,255,0.06);
  overflow: hidden;
  position: relative;
}

.phone-frame__inner {
  padding: 24px 16px;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.phone-frame__notch {
  width: 60px;
  height: 18px;
  background: #000;
  border-radius: 10px;
  margin: 0 auto 8px;
}

.phone-frame__line {
  height: 8px;
  background: linear-gradient(90deg, var(--cyan-glow), transparent);
  border-radius: 4px;
  animation: pulse-line 3s ease-in-out infinite;
}

.phone-frame__line--short { width: 55%; opacity: 0.5; animation-delay: 0.5s; }
.phone-frame__line--mid   { width: 75%; opacity: 0.7; animation-delay: 1s; }

@keyframes pulse-line {
  0%, 100% { opacity: 0.3; }
  50%       { opacity: 1; }
}

.phone-frame__dot {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: var(--cyan-glow);
  border: 2px solid var(--cyan-dim);
  margin-top: 12px;
  animation: pulse-dot 2s ease-in-out infinite;
}

@keyframes pulse-dot {
  0%, 100% { box-shadow: 0 0 0 0 var(--cyan-glow); }
  50%       { box-shadow: 0 0 0 10px transparent; }
}

.hero__ring {
  position: absolute;
  border-radius: 50%;
  border: 1px solid var(--border2);
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  opacity: 0.4;
  animation: expandRing 4s ease-out infinite;
}

.hero__ring--1 { width: 260px; height: 260px; animation-delay: 0s; }
.hero__ring--2 { width: 340px; height: 340px; animation-delay: 2s; }

@keyframes expandRing {
  0%   { opacity: 0.4; transform: translate(-50%, -50%) scale(0.9); }
  100% { opacity: 0;   transform: translate(-50%, -50%) scale(1.2); }
}

/* =============================================
   STATS BAR
   ============================================= */
.stats-bar {
  background: var(--surface);
  border-top: 1px solid var(--border);
  border-bottom: 1px solid var(--border);
  display: grid;
  grid-template-columns: repeat(4, 1fr);
}

.stats-bar__item {
  padding: 20px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
  border-right: 1px solid var(--border);
}

.stats-bar__item:last-child { border-right: none; }

.stats-bar__item strong {
  font-family: var(--font-display);
  font-size: 22px;
  font-weight: 700;
  color: var(--cyan);
}

.stats-bar__item span {
  font-size: 12px;
  color: var(--text-muted);
  letter-spacing: 0.05em;
}

/* =============================================
   BUTTONS
   ============================================= */
.btn {
  font-family: var(--font-display);
  font-size: 13px;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  border: none;
  cursor: pointer;
  padding: 12px 26px;
  border-radius: var(--r-sm);
  transition: all 0.2s var(--ease);
  white-space: nowrap;
  text-decoration: none;
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.btn--primary {
  background: var(--cyan);
  color: #000;
  box-shadow: 0 0 20px rgba(0,212,255,0.3);
}

.btn--primary:hover {
  background: #33ddff;
  box-shadow: 0 0 30px rgba(0,212,255,0.5);
  transform: translateY(-1px);
}

.btn--outline {
  background: transparent;
  color: var(--cyan);
  border: 1px solid var(--cyan-dim);
}

.btn--outline:hover {
  background: var(--cyan-glow);
  border-color: var(--cyan);
}

.btn--ghost {
  background: var(--surface);
  color: var(--text-muted);
  border: 1px solid var(--border);
}

.btn--ghost:hover { color: var(--text); border-color: var(--text-dim); }

.btn--full { width: 100%; }

.btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
  transform: none !important;
}

/* =============================================
   MAIN / PRODUCTS SECTION
   ============================================= */
.main {
  max-width: 1280px;
  margin: 0 auto;
  padding: 60px 24px 80px;
}

.section-head {
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  margin-bottom: 36px;
  flex-wrap: wrap;
  gap: 16px;
}

.section-head__tag {
  font-family: var(--font-display);
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.2em;
  color: var(--cyan);
  display: block;
  margin-bottom: 6px;
}

.section-head__title {
  font-family: var(--font-display);
  font-size: 32px;
  font-weight: 700;
  color: var(--text);
}

.filter-chips {
  display: flex;
  gap: 8px;
}

.filter-chip {
  font-family: var(--font-display);
  font-size: 12px;
  font-weight: 500;
  letter-spacing: 0.06em;
  padding: 8px 18px;
  border-radius: var(--r-full);
  border: 1px solid var(--border);
  background: transparent;
  color: var(--text-muted);
  cursor: pointer;
  transition: all 0.2s;
}

.filter-chip:hover,
.filter-chip.active {
  border-color: var(--cyan);
  color: var(--cyan);
  background: var(--cyan-glow);
}

/* =============================================
   PRODUCTS GRID
   ============================================= */
.products-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 20px;
}

.product-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--r-lg);
  overflow: hidden;
  cursor: pointer;
  transition: all 0.3s var(--ease);
  animation: fadeUp 0.5s var(--ease) both;
  display: flex;
  flex-direction: column;
}

.product-card:hover {
  border-color: var(--border2);
  transform: translateY(-4px);
  box-shadow: 0 20px 60px rgba(0,0,0,0.5), 0 0 0 1px var(--border2);
}

.product-card__img-wrap {
  position: relative;
  background: var(--surface);
  aspect-ratio: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
}

.product-card__img {
  width: 75%;
  height: 75%;
  object-fit: contain;
  transition: transform 0.4s var(--ease);
}

.product-card:hover .product-card__img {
  transform: scale(1.07);
}

.product-card__badge {
  position: absolute;
  top: 10px;
  left: 10px;
  background: var(--cyan);
  color: #000;
  font-family: var(--font-display);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.08em;
  padding: 3px 8px;
  border-radius: 4px;
}

.product-card__sale {
  position: absolute;
  top: 10px;
  right: 10px;
  background: var(--error);
  color: #fff;
  font-family: var(--font-display);
  font-size: 10px;
  font-weight: 700;
  padding: 3px 8px;
  border-radius: 4px;
}

.product-card__body {
  padding: 16px;
  display: flex;
  flex-direction: column;
  flex: 1;
}

.product-card__brand {
  font-family: var(--font-display);
  font-size: 10px;
  font-weight: 600;
  letter-spacing: 0.15em;
  color: var(--cyan-dim);
  text-transform: uppercase;
  margin-bottom: 4px;
}

.product-card__name {
  font-family: var(--font-display);
  font-size: 14px;
  font-weight: 600;
  color: var(--text);
  margin-bottom: 8px;
  line-height: 1.4;
  flex: 1;
}

.product-card__price-row {
  display: flex;
  align-items: baseline;
  gap: 8px;
  margin-bottom: 12px;
}

.product-card__price {
  font-family: var(--font-display);
  font-size: 18px;
  font-weight: 700;
  color: var(--cyan);
}

.product-card__original {
  font-size: 13px;
  color: var(--text-dim);
  text-decoration: line-through;
}

.product-card__footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.product-card__stock {
  font-size: 12px;
  color: var(--text-muted);
}

.product-card__stock--low { color: var(--gold); }

.product-card__add {
  font-family: var(--font-display);
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  background: var(--cyan);
  color: #000;
  border: none;
  border-radius: var(--r-sm);
  padding: 7px 14px;
  cursor: pointer;
  transition: all 0.2s;
}

.product-card__add:hover {
  background: #33ddff;
  box-shadow: 0 0 16px rgba(0,212,255,0.4);
}

/* STATES */
.loading-state {
  grid-column: 1 / -1;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 16px;
  padding: 60px;
  color: var(--text-muted);
}

.spinner {
  width: 32px;
  height: 32px;
  border: 3px solid var(--border);
  border-top-color: var(--cyan);
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

@keyframes spin { to { transform: rotate(360deg); } }

.error-state {
  grid-column: 1 / -1;
  padding: 40px;
  text-align: center;
  color: var(--error);
  background: rgba(255,71,87,0.05);
  border: 1px solid rgba(255,71,87,0.2);
  border-radius: var(--r-lg);
}

.empty-state {
  grid-column: 1 / -1;
  text-align: center;
  padding: 60px;
  color: var(--text-muted);
}

.empty-state__icon {
  font-size: 48px;
  margin-bottom: 12px;
}

/* =============================================
   PRODUCT DETAIL MODAL
   ============================================= */
.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.75);
  backdrop-filter: blur(6px);
  z-index: 200;
  display: none;
  align-items: center;
  justify-content: center;
  padding: 24px;
}

.modal-overlay.open {
  display: flex;
  animation: fadeIn 0.2s var(--ease);
}

@keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }

.modal {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--r-xl);
  width: 100%;
  max-width: 760px;
  max-height: 90vh;
  overflow-y: auto;
  position: relative;
  animation: slideUp 0.3s var(--ease);
}

@keyframes slideUp {
  from { opacity: 0; transform: translateY(20px); }
  to   { opacity: 1; transform: translateY(0); }
}

.modal__close {
  position: absolute;
  top: 16px;
  right: 16px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 50%;
  width: 32px;
  height: 32px;
  font-size: 18px;
  color: var(--text-muted);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 10;
  line-height: 1;
  transition: all 0.2s;
}

.modal__close:hover { color: var(--text); border-color: var(--text-dim); }

/* Product detail content */
.product-detail {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0;
}

.product-detail__img-side {
  background: var(--surface);
  border-radius: var(--r-xl) 0 0 var(--r-xl);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 40px;
  min-height: 380px;
}

.product-detail__img {
  max-width: 200px;
  max-height: 280px;
  object-fit: contain;
}

.product-detail__info {
  padding: 40px 36px 36px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.product-detail__brand {
  font-family: var(--font-display);
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.18em;
  color: var(--cyan);
  text-transform: uppercase;
}

.product-detail__name {
  font-family: var(--font-display);
  font-size: 22px;
  font-weight: 700;
  line-height: 1.3;
}

.product-detail__desc {
  font-size: 14px;
  color: var(--text-muted);
  line-height: 1.7;
}

.product-detail__price-group {
  display: flex;
  align-items: baseline;
  gap: 10px;
}

.product-detail__price {
  font-family: var(--font-display);
  font-size: 28px;
  font-weight: 700;
  color: var(--cyan);
}

.product-detail__orig {
  font-size: 15px;
  color: var(--text-dim);
  text-decoration: line-through;
}

.product-detail__specs {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8px;
}

.spec-item {
  background: var(--surface);
  border-radius: var(--r-sm);
  padding: 8px 10px;
}

.spec-item__label {
  font-size: 10px;
  color: var(--text-dim);
  text-transform: uppercase;
  letter-spacing: 0.08em;
  display: block;
}

.spec-item__val {
  font-family: var(--font-display);
  font-size: 13px;
  font-weight: 600;
  color: var(--text);
}

.product-detail__actions {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-top: 4px;
}

.qty-control {
  display: flex;
  align-items: center;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--r-sm);
  overflow: hidden;
}

.qty-btn {
  background: transparent;
  border: none;
  color: var(--text);
  width: 36px;
  height: 36px;
  font-size: 18px;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: background 0.15s;
}

.qty-btn:hover { background: var(--border); }

.qty-val {
  font-family: var(--font-display);
  font-size: 14px;
  font-weight: 600;
  min-width: 36px;
  text-align: center;
  color: var(--text);
}

/* =============================================
   CART SIDEBAR
   ============================================= */
.cart-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.5);
  z-index: 300;
  display: none;
}

.cart-overlay.open {
  display: block;
  animation: fadeIn 0.2s;
}

.cart {
  position: fixed;
  right: 0;
  top: 0;
  bottom: 0;
  width: 380px;
  max-width: 100vw;
  background: var(--bg-card2);
  border-left: 1px solid var(--border);
  display: flex;
  flex-direction: column;
  z-index: 301;
  animation: slideRight 0.3s var(--ease);
}

@keyframes slideRight {
  from { transform: translateX(100%); }
  to   { transform: translateX(0); }
}

.cart__header {
  padding: 20px 24px;
  border-bottom: 1px solid var(--border);
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-shrink: 0;
}

.cart__header h3 {
  font-family: var(--font-display);
  font-size: 16px;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.cart__close {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 50%;
  width: 30px;
  height: 30px;
  font-size: 17px;
  color: var(--text-muted);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.15s;
}

.cart__close:hover { color: var(--text); }

.cart__items {
  flex: 1;
  overflow-y: auto;
  padding: 16px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.cart-item {
  display: grid;
  grid-template-columns: 64px 1fr auto;
  gap: 12px;
  align-items: center;
  background: var(--surface);
  border-radius: var(--r-md);
  padding: 10px;
}

.cart-item__img {
  width: 64px;
  height: 64px;
  object-fit: contain;
  background: var(--bg-card);
  border-radius: var(--r-sm);
}

.cart-item__name {
  font-size: 13px;
  font-weight: 500;
  color: var(--text);
  line-height: 1.4;
  margin-bottom: 4px;
}

.cart-item__price {
  font-family: var(--font-display);
  font-size: 14px;
  font-weight: 700;
  color: var(--cyan);
}

.cart-item__controls {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: 6px;
}

.cart-item__qty {
  display: flex;
  align-items: center;
  gap: 4px;
  background: var(--bg-card);
  border-radius: var(--r-sm);
  overflow: hidden;
}

.cart-item__qty-btn {
  background: transparent;
  border: none;
  color: var(--text-muted);
  width: 26px;
  height: 26px;
  cursor: pointer;
  font-size: 14px;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: color 0.15s;
}

.cart-item__qty-btn:hover { color: var(--cyan); }

.cart-item__qty-val {
  font-family: var(--font-display);
  font-size: 13px;
  font-weight: 600;
  min-width: 20px;
  text-align: center;
}

.cart-item__remove {
  background: transparent;
  border: none;
  color: var(--text-dim);
  cursor: pointer;
  font-size: 12px;
  padding: 2px;
  transition: color 0.15s;
}

.cart-item__remove:hover { color: var(--error); }

.cart__footer {
  padding: 20px 24px;
  border-top: 1px solid var(--border);
  flex-shrink: 0;
}

.cart__total-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 14px;
  font-size: 14px;
}

.cart__total-row strong {
  font-family: var(--font-display);
  font-size: 20px;
  font-weight: 700;
  color: var(--cyan);
}

/* =============================================
   CHECKOUT MODAL
   ============================================= */
.modal--checkout {
  max-width: 560px;
  padding: 40px;
}

.modal__title {
  font-family: var(--font-display);
  font-size: 22px;
  font-weight: 700;
  margin-bottom: 24px;
  padding-right: 40px;
}

.form-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
}

.form-group {
  margin-bottom: 16px;
}

.form-label {
  font-size: 12px;
  font-weight: 500;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--text-muted);
  display: block;
  margin-bottom: 6px;
}

.form-input {
  width: 100%;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--r-sm);
  color: var(--text);
  font-family: var(--font-body);
  font-size: 14px;
  padding: 10px 14px;
  outline: none;
  transition: border-color 0.2s;
}

.form-input:focus { border-color: var(--cyan-dim); }
.form-input::placeholder { color: var(--text-dim); }

.form-textarea { resize: vertical; min-height: 80px; }

.form-error {
  color: var(--error);
  font-size: 11px;
  margin-top: 4px;
}

.order-review {
  background: var(--surface);
  border-radius: var(--r-md);
  padding: 16px;
  margin-bottom: 16px;
}

.order-review__title {
  font-family: var(--font-display);
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--text-muted);
  margin-bottom: 12px;
}

.order-review__item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 13px;
  color: var(--text-muted);
  padding: 6px 0;
  border-bottom: 1px solid var(--border);
}

.order-review__item:last-of-type { border-bottom: none; }

.order-review__item span:last-child {
  font-family: var(--font-display);
  font-weight: 600;
  color: var(--text);
}

.order-review__total {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding-top: 12px;
  border-top: 1px solid var(--border2);
  font-size: 13px;
  color: var(--text-muted);
}

.order-review__total strong {
  font-family: var(--font-display);
  font-size: 18px;
  font-weight: 700;
  color: var(--cyan);
}

.alert {
  border-radius: var(--r-sm);
  padding: 10px 14px;
  font-size: 13px;
  margin-bottom: 14px;
}

.alert--error {
  background: rgba(255,71,87,0.1);
  border: 1px solid rgba(255,71,87,0.3);
  color: var(--error);
}

/* =============================================
   SUCCESS MODAL
   ============================================= */
.modal--success {
  max-width: 420px;
  padding: 0;
}

.success-body {
  padding: 48px 40px;
  text-align: center;
}

.success-icon {
  width: 64px;
  height: 64px;
  background: rgba(46,213,115,0.15);
  border: 2px solid var(--success);
  border-radius: 50%;
  font-size: 28px;
  font-weight: 700;
  color: var(--success);
  display: flex;
  align-items: center;
  justify-content: center;
  margin: 0 auto 20px;
}

.success-body h2 {
  font-family: var(--font-display);
  font-size: 22px;
  font-weight: 700;
  margin-bottom: 12px;
}

.success-body p {
  font-size: 14px;
  color: var(--text-muted);
  line-height: 1.7;
  margin-bottom: 24px;
}

/* =============================================
   FOOTER
   ============================================= */
.footer {
  background: var(--surface);
  border-top: 1px solid var(--border);
  margin-top: 40px;
}

.footer__inner {
  max-width: 1280px;
  margin: 0 auto;
  padding: 40px 24px;
  display: flex;
  justify-content: space-between;
  gap: 32px;
  flex-wrap: wrap;
}

.footer__brand .logo { margin-bottom: 8px; }
.footer__brand p { font-size: 13px; color: var(--text-muted); margin-top: 6px; }

.footer__contact {
  display: flex;
  flex-direction: column;
  gap: 6px;
  font-size: 13px;
  color: var(--text-muted);
}

.footer__contact strong { color: var(--text); }

.footer__copy {
  text-align: center;
  padding: 16px 24px;
  border-top: 1px solid var(--border);
  font-size: 12px;
  color: var(--text-dim);
  letter-spacing: 0.05em;
}

/* =============================================
   RESPONSIVE
   ============================================= */
@media (max-width: 1024px) {
  .hero__visual { display: none; }
  .hero__title { font-size: clamp(40px, 8vw, 64px); }
}

@media (max-width: 768px) {
  .header__inner { gap: 12px; }
  .nav { display: none; }
  .search-input { width: 130px; }
  .hero { padding: 60px 20px; min-height: 70vh; }
  .stats-bar { grid-template-columns: repeat(2, 1fr); }
  .stats-bar__item:nth-child(2) { border-right: none; }
  .product-detail { grid-template-columns: 1fr; }
  .product-detail__img-side { border-radius: var(--r-xl) var(--r-xl) 0 0; min-height: 240px; }
  .form-row { grid-template-columns: 1fr; }
  .modal--checkout { padding: 24px 20px; }
  .main { padding: 40px 16px 60px; }
}

@media (max-width: 480px) {
  .cart { width: 100vw; }
  .hero__cta { flex-direction: column; }
  .hero__cta .btn { width: 100%; text-align: center; }
  .section-head { flex-direction: column; align-items: flex-start; }
}
