/**
 * NEXUS PHONE — Main Application
 */

// ── State ──────────────────────────────────────────────────────────
const state = {
  phones: [],
  currentSlug: '',
  currentSearch: '',
  featuredOnly: false,
  cart: [],            // [{ phone, qty }]
};

// ── Init ───────────────────────────────────────────────────────────
document.addEventListener('DOMContentLoaded', () => {
  loadPhones();
});

// ── Load phones ────────────────────────────────────────────────────
async function loadPhones() {
  const grid = document.getElementById('products-grid');
  grid.innerHTML = '<div class="loading-state"><div class="spinner"></div><p>Đang tải sản phẩm...</p></div>';

  const params = {};
  if (state.currentSlug)   params.category = state.currentSlug;
  if (state.featuredOnly)  params.featured  = true;
  if (state.currentSearch) params.search    = state.currentSearch;

  try {
    const phones = await api.get('/api/phones', params);
    state.phones = phones;
    renderPhones(phones);
  } catch (err) {
    grid.innerHTML = `<div class="error-state"><p>Không thể tải sản phẩm: ${escapeHtml(err.message)}</p></div>`;
  }
}

function renderPhones(phones) {
  const grid = document.getElementById('products-grid');
  if (!phones.length) {
    grid.innerHTML = '<div class="empty-state"><div class="empty-state__icon">📱</div><p>Không tìm thấy sản phẩm phù hợp</p></div>';
    return;
  }
  grid.innerHTML = phones.map((p, i) => buildPhoneCard(p, i)).join('');
}

function buildPhoneCard(p, i) {
  const sale = p.original_price && p.original_price > p.price
    ? Math.round((1 - p.price / p.original_price) * 100)
    : null;
  const delay = (i % 8) * 0.05;
  return `
    <article class="product-card" style="animation-delay:${delay}s" onclick="openProductDetail(${p.id})">
      <div class="product-card__img-wrap">
        ${p.is_featured ? '<span class="product-card__badge">⭐ Nổi bật</span>' : ''}
        ${sale ? `<span class="product-card__sale">-${sale}%</span>` : ''}
        <img class="product-card__img" src="${escapeHtml(p.image_url || '')}" alt="${escapeHtml(p.name)}" loading="lazy"
             onerror="this.src='data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 width=%22100%22 height=%22100%22><rect fill=%22%23161d2a%22 width=%22100%22 height=%22100%22/><text fill=%22%236b7a99%22 x=%2250%22 y=%2255%22 text-anchor=%22middle%22 font-size=%2230%22>📱</text></svg>'" />
      </div>
