// ── Product Detail ─────────────────────────────────────────────────
async function openProductDetail(phoneId) {
  const modal = document.getElementById('product-modal');
  const content = document.getElementById('modal-content');
  content.innerHTML = '<div class="loading-state" style="min-height:300px"><div class="spinner"></div></div>';
  modal.classList.add('open');
  document.body.style.overflow = 'hidden';

  try {
    const p = await api.get(`/api/phones/${phoneId}`);
    content.innerHTML = buildDetailHTML(p);
  } catch (err) {
    content.innerHTML = `<div class="error-state" style="padding:40px"><p>${escapeHtml(err.message)}</p></div>`;
  }
}

function buildDetailHTML(p) {
  const specs = p.specs || {};
  const specKeys = { ram: 'RAM', storage: 'Bộ nhớ', screen: 'Màn hình', camera: 'Camera', battery: 'Pin', chip: 'Chip' };
  const specsHTML = Object.entries(specKeys)
    .filter(([k]) => specs[k])
    .map(([k, label]) => `
      <div class="spec-item">
        <span class="spec-item__label">${label}</span>
        <span class="spec-item__val">${escapeHtml(specs[k])}</span>
      </div>`).join('');

  const sale = p.original_price && p.original_price > p.price
    ? Math.round((1 - p.price / p.original_price) * 100) : null;

  return `
    <div class="product-detail">
      <div class="product-detail__img-side">
        <img class="product-detail__img" src="${escapeHtml(p.image_url || '')}" alt="${escapeHtml(p.name)}"
             onerror="this.src='data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 width=%22200%22 height=%22200%22><rect fill=%22%23161d2a%22 width=%22200%22 height=%22200%22/><text fill=%22%236b7a99%22 x=%22100%22 y=%22110%22 text-anchor=%22middle%22 font-size=%2260%22>📱</text></svg>'" />
      </div>
      <div class="product-detail__info">
        <div class="product-detail__brand">${escapeHtml(p.brand)}</div>
        <h2 class="product-detail__name">${escapeHtml(p.name)}</h2>
        <p class="product-detail__desc">${escapeHtml(p.description || '')}</p>
        <div class="product-detail__price-group">
          <span class="product-detail__price">${formatPrice(p.price)}</span>
          ${p.original_price ? `<span class="product-detail__orig">${formatPrice(p.original_price)}</span>` : ''}
          ${sale ? `<span style="background:var(--error);color:#fff;font-family:var(--font-display);font-size:11px;font-weight:700;padding:3px 8px;border-radius:4px">-${sale}%</span>` : ''}
        </div>
        ${specsHTML ? `<div class="product-detail__specs">${specsHTML}</div>` : ''}
        <div class="product-detail__actions">
          <div class="qty-control">
            <button class="qty-btn" onclick="changeDetailQty(-1)">−</button>
            <span class="qty-val" id="detail-qty">1</span>
            <button class="qty-btn" onclick="changeDetailQty(1)">+</button>
          </div>
          <button class="btn btn--primary" style="flex:1"
            onclick="addToCartFromDetail(${p.id}, '${escapeHtml(p.name).replace(/'/g, "\\'")}', ${p.price}, '${escapeHtml(p.image_url || '')}')"
            ${p.stock === 0 ? 'disabled' : ''}>
            ${p.stock === 0 ? 'Hết hàng' : '+ Thêm vào giỏ'}
          </button>
        </div>
        <p style="font-size:12px;color:var(--text-muted)">
          ${p.stock > 0 ? `✓ Còn ${p.stock} sản phẩm` : '✗ Hết hàng'}
