          <div class="qty-control">
            <button class="qty-btn" onclick="changeDetailQty(-1)">−</button>
            <span class="qty-val" id="detail-qty">1</span>
            <button class="qty-btn" onclick="changeDetailQty(1)">+</button>
          </div>
          <button class="btn btn--primary" style="flex:1"
            onclick="addToCartFromDetail(${p.id}, '${escapeHtml(p.name).replace(/'/g, "\\'")}', ${p.price}, '${escapeHtml(p.image_url || '')}')"
            ${p.stock === 0 ? 'disabled' : ''}>
            ${p.stock === 0 ? 'Hết hàng' : '+ Thêm vào giỏ'}
          </button>
        </div>
        <p style="font-size:12px;color:var(--text-muted)">
          ${p.stock > 0 ? `✓ Còn ${p.stock} sản phẩm` : '✗ Hết hàng'}
        </p>
      </div>
    </div>`;
}

function changeDetailQty(delta) {
  const el = document.getElementById('detail-qty');
  if (!el) return;
  const v = Math.max(1, parseInt(el.textContent) + delta);
  el.textContent = v;
}

// ── Cart ───────────────────────────────────────────────────────────
function addToCartFromCard(event, phoneId) {
  event.stopPropagation();
  const phone = state.phones.find(p => p.id === phoneId);
  if (!phone) return;
  addToCart(phone, 1);
}

function addToCartFromDetail(phoneId, name, price, imageUrl) {
  const qty = parseInt(document.getElementById('detail-qty')?.textContent || '1');
  const phone = state.phones.find(p => p.id === phoneId)
    || { id: phoneId, name, price, image_url: imageUrl };
  addToCart(phone, qty);
  closeModal('product-modal');
}

function addToCart(phone, qty) {
  const existing = state.cart.find(i => i.phone.id === phone.id);
  if (existing) {
    existing.qty += qty;
  } else {
    state.cart.push({ phone, qty });
  }
  renderCart();
  openCart();
}

function removeFromCart(phoneId) {
  state.cart = state.cart.filter(i => i.phone.id !== phoneId);
  renderCart();
}

function changeCartQty(phoneId, delta) {
  const item = state.cart.find(i => i.phone.id === phoneId);
  if (!item) return;
  item.qty = Math.max(1, item.qty + delta);
  renderCart();
}

function renderCart() {
  const itemsEl = document.getElementById('cart-items');
  const footerEl = document.getElementById('cart-footer');
  const badge = document.getElementById('cart-badge');
  const totalEl = document.getElementById('cart-total-price');

  const totalQty = state.cart.reduce((s, i) => s + i.qty, 0);
  const totalAmt = state.cart.reduce((s, i) => s + i.phone.price * i.qty, 0);
  badge.textContent = totalQty;

  if (!state.cart.length) {
    itemsEl.innerHTML = '<div class="empty-state"><div class="empty-state__icon">🛒</div><p>Giỏ hàng trống</p></div>';
    footerEl.style.display = 'none';
    return;
  }

  footerEl.style.display = 'block';
  totalEl.textContent = formatPrice(totalAmt);

  itemsEl.innerHTML = state.cart.map(item => `
    <div class="cart-item">
      <img class="cart-item__img" src="${escapeHtml(item.phone.image_url || '')}" alt="${escapeHtml(item.phone.name)}"
           onerror="this.src='data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 width=%2264%22 height=%2264%22><rect fill=%22%23161d2a%22 width=%2264%22 height=%2264%22/><text fill=%22%236b7a99%22 x=%2232%22 y=%2238%22 text-anchor=%22middle%22 font-size=%2224%22>📱</text></svg>'" />
      <div>
        <div class="cart-item__name">${escapeHtml(item.phone.name)}</div>
        <div class="cart-item__price">${formatPrice(item.phone.price * item.qty)}</div>
      </div>
      <div class="cart-item__controls">
        <div class="cart-item__qty">
          <button class="cart-item__qty-btn" onclick="changeCartQty(${item.phone.id}, -1)">−</button>
          <span class="cart-item__qty-val">${item.qty}</span>
          <button class="cart-item__qty-btn" onclick="changeCartQty(${item.phone.id}, 1)">+</button>
        </div>
        <button class="cart-item__remove" onclick="removeFromCart(${item.phone.id})">✕ Xóa</button>
      </div>
    </div>`).join('');
}

function openCart() {
  const overlay = document.getElementById('cart-overlay');
  overlay.classList.add('open');
  document.body.style.overflow = 'hidden';
}

function toggleCart() {
  const overlay = document.getElementById('cart-overlay');
  if (overlay.classList.contains('open')) {
    overlay.classList.remove('open');
    document.body.style.overflow = '';
  } else {
    openCart();
  }
}

function handleCartOverlayClick(event) {
  if (event.target === document.getElementById('cart-overlay')) {
    toggleCart();
  }
}

// ── Checkout ───────────────────────────────────────────────────────
function showCheckout() {
  // populate order review
  const total = state.cart.reduce((s, i) => s + i.phone.price * i.qty, 0);
  document.getElementById('order-review-items').innerHTML = state.cart.map(i => `
    <div class="order-review__item">
      <span>${escapeHtml(i.phone.name)} × ${i.qty}</span>
      <span>${formatPrice(i.phone.price * i.qty)}</span>
    </div>`).join('');
  document.getElementById('order-review-total').textContent = formatPrice(total);

  // hide cart, show checkout
  document.getElementById('cart-overlay').classList.remove('open');
  document.getElementById('checkout-modal').classList.add('open');
}

function closeCheckout() {
  closeModal('checkout-modal');
}

function closeCheckoutOverlay(event) {
  if (event.target === document.getElementById('checkout-modal')) closeCheckout();
}

async function submitOrder(event) {
  event.preventDefault();
  const form = event.target;
  const data = getFormData(form);
  const errEl = document.getElementById('checkout-error');
  errEl.style.display = 'none';

  // validate
  const errors = {};
  if (!data.customer_name?.trim()) errors.customer_name = 'Vui lòng nhập họ và tên';
  if (!data.customer_phone?.trim()) errors.customer_phone = 'Vui lòng nhập số điện thoại';
  if (!data.customer_address?.trim()) errors.customer_address = 'Vui lòng nhập địa chỉ';
  if (!/^0[0-9]{9,10}$/.test(data.customer_phone?.replace(/\s/g, ''))) {
    errors.customer_phone = 'Số điện thoại không hợp lệ';
  }

  showFormErrors(form, errors);
  if (Object.keys(errors).length) return;

  const submitBtn = document.getElementById('submit-btn');
  submitBtn.disabled = true;
  submitBtn.textContent = 'Đang xử lý...';

  try {
    const payload = {
      customer_name: data.customer_name.trim(),
      customer_phone: data.customer_phone.replace(/\s/g, ''),
      customer_address: data.customer_address.trim(),
      note: data.note?.trim() || null,
      items: state.cart.map(i => ({ phone_id: i.phone.id, quantity: i.qty })),
    };
    await api.post('/api/phones/orders', payload);

    // success
    state.cart = [];
    renderCart();
    closeModal('checkout-modal');
    document.getElementById('success-modal').classList.add('open');
    form.reset();
  } catch (err) {
    errEl.style.display = 'block';
    errEl.textContent = err.message;
  } finally {
    submitBtn.disabled = false;
    submitBtn.textContent = 'Xác nhận đặt hàng';
  }
}

function closeSuccess() {
  document.getElementById('success-modal').classList.remove('open');
  document.body.style.overflow = '';
  loadPhones(); // refresh stock
}

// ── Modal helpers ──────────────────────────────────────────────────
function closeModal(modalId) {
  document.getElementById(modalId).classList.remove('open');
  document.body.style.overflow = '';
}

function handleModalOverlayClick(event, modalId) {
  if (event.target === document.getElementById(modalId)) closeModal(modalId);
}

// ── Utils ──────────────────────────────────────────────────────────
function escapeHtml(text) {
  if (text === null || text === undefined) return '';
  const div = document.createElement('div');
  div.textContent = String(text);
  return div.innerHTML;
}

function formatPrice(value) {
  const n = Number(value);
  if (isNaN(n)) return '0đ';
  return n.toLocaleString('vi-VN') + 'đ';
}

function getFormData(form) {
  const fd = new FormData(form);
  const obj = {};
  for (const [k, v] of fd.entries()) obj[k] = v;
  return obj;
}

function showFormErrors(form, errors) {
  form.querySelectorAll('.form-error').forEach(el => el.remove());
  form.querySelectorAll('.form-input, .form-textarea').forEach(el => el.style.borderColor = '');
  for (const [field, msg] of Object.entries(errors)) {
    const input = form.querySelector(`[name="${field}"]`);
    if (input) {
      input.style.borderColor = 'var(--error)';
      const p = document.createElement('p');
      p.className = 'form-error';
      p.textContent = msg;
      input.parentNode.appendChild(p);
    }
  }
}
